function estimateBitStreamSizeOfEntry( $version ) {
		$bits = 0;

		if ( 0 === $version ) {
			$version = 1;
		}

		switch ( $this->mode ) {
			case QR_MODE_NUM:
				$bits = QRinput::estimateBitsModeNum( $this->size );
				break;
			case QR_MODE_AN:
				$bits = QRinput::estimateBitsModeAn( $this->size );
				break;
			case QR_MODE_8:
				$bits = QRinput::estimateBitsMode8( $this->size );
				break;
			case QR_MODE_KANJI:
				$bits = QRinput::estimateBitsModeKanji( $this->size );
				break;
			case QR_MODE_STRUCTURE:
				return STRUCTURE_HEADER_BITS;
			default:
				return 0;
		}

		$l   = QRspec::lengthIndicator( $this->mode, $version );
		$m   = 1 << $l;
