/**
		 * Update order question in quiz.
		 *
		 * @param array $order Array of question IDs in display order.
		 *
		 * @return false|int Number of rows updated, or false on failure.
		 */
function sort_questions( $order ) {
			global $wpdb;

			if ( empty( $order ) ) {
				return 0;
			}

			// Build a single CASE WHEN UPDATE to set all question_order values at once.
			$case_sql    = '';
			$ids         = array();
			foreach ( $order as $index => $question_id ) {
				$case_sql .= $wpdb->prepare( 'WHEN question_id = %d THEN %d ', (int) $question_id, $index + 1 );
				$ids[]     = (int) $question_id;
			}

			$ids_placeholders = implode( ', ', array_fill( 0, count( $ids ), '%d' ) );

			// phpcs:ignore WordPress.DB.DirectDatabaseQuery, WordPress.DB.PreparedSQL.InterpolatedNotPrepared
			$result = $wpdb->query(
				$wpdb->prepare(
					"UPDATE {$wpdb->learnpress_quiz_questions} SET question_order = CASE {$case_sql} ELSE question_order END WHERE question_id IN ( {$ids_placeholders} )", // phpcs:ignore WordPress.DB.PreparedSQL.InterpolatedNotPrepared
					...$ids
				)
			);

			return ( false === $result ) ? false : (int) $result;
