		$data  = array_fill( 0, (int) ( ( $size + 7 ) / 8 ), 0 );
		$bytes = (int) ( $size / 8 );

		$p = 0;

		for ( $i = 0; $i < $bytes; $i++ ) {
			$v = 0;
			for ( $j = 0; $j < 8; $j++ ) {
				$v   = $v << 1;
				$v  |= $this->data[ $p ];
				$p++;
			}
			$data[ $i ] = $v;
		}

		if ( $size & 7 ) {
			$v = 0;
			for ( $j = 0; $j < ( $size & 7 ); $j++ ) {
				$v   = $v << 1;
				$v  |= $this->data[ $p ];
				$p++;
			}
			$data[ $bytes ] = $v;
		}

		return $data;
