/**
	 * Updates all the user's active subscriptions payment method with the new payment method.
	 *
	 * @since 8.8.0
	 *
	 * @param int      $user_id               The user ID.
	 * @param stdClass $payment_method_object The newly added payment method object.
	 * @return void
	 */
function handle_upe_add_payment_method_success( $user_id, $payment_method_object ) {
		if ( ! class_exists( 'WC_Subscriptions_Change_Payment_Gateway' ) || ! isset( $payment_method_object->id ) ) {
			return;
		}

		// Verify nonce before reading any request data.
		$nonce_action = 'wc-stripe-update-subs-payment-method-' . $this->id;
		if ( isset( $_POST[ '_wpnonce_' . $this->id ] ) ) {
			check_admin_referer( $nonce_action, '_wpnonce_' . $this->id );
		}

		$should_update_subscriptions = isset( $_POST[ 'wc-' . $this->id . '-update-subs-payment-method-card' ] );

		if ( $should_update_subscriptions ) {
			$subscriptions = wcs_get_users_subscriptions( $user_id );
			foreach ( $subscriptions as $subscription ) {
				if ( $subscription->has_status( array( 'active', 'past-due', 'on-hold' ) ) ) {
					$subscription->set_payment_method( $this->id );
					$subscription->set_payment_method_meta( $this->id, $payment_method_object );
					$subscription->save();
				}
			}
		}
	}

