function getLockers(): array
    {
        global $wpdb;

        $table      = $wpdb->prefix . $this->tableName;
        $is_testing = SamedayCourierHelperClass::isTesting();

        // buildGridQuery returns a prepared query string with args; apply prepare() defensively.
        $query_data = SamedayCourierHelperClass::buildGridQueryPrepared(
            $table,
            $is_testing,
            self::ACCEPTED_FILTERS,
        );

        // phpcs:ignore WordPress.DB.DirectDatabaseQuery, WordPress.DB.PreparedSQL.NotPrepared
        return $wpdb->get_results(
            $wpdb->prepare( $query_data['sql'], ...$query_data['args'] ),
            'ARRAY_A'
        );
    }

